import{_ as t,o as a,c as o,ag as d}from"./chunks/framework.DLWhSH9p.js";const p=JSON.parse('{"title":"AI Providers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-providers.md","filePath":"guide/ai-providers.md"}'),r={name:"guide/ai-providers.md"};function i(l,e,s,n,c,u){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="ai-providers" tabindex="-1">AI Providers <a class="header-anchor" href="#ai-providers" aria-label="Permalink to &quot;AI Providers&quot;">​</a></h1><p>CRAFT Studio supports three AI providers. All can be active at once — pick per-request from the model dropdown. API keys are <strong>per-user</strong> and stored encrypted on the server — set them in <strong>Avatar menu → API Keys</strong>.</p><h2 id="gemini-google" tabindex="-1">Gemini (Google) <a class="header-anchor" href="#gemini-google" aria-label="Permalink to &quot;Gemini (Google)&quot;">​</a></h2><p>Paste a Gemini API key in the API Keys modal under the <strong>Gemini</strong> field.</p><p>Get a key at <a href="https://ai.google.dev/gemini-api/docs/api-key" target="_blank" rel="noreferrer">ai.google.dev</a>.</p><p><strong>Characteristics</strong></p><ul><li>Streams responses token-by-token (real-time)</li><li>Reliable with standard API keys</li><li>Good for quick iterations</li><li>Free tier is usually enough to explore the studio</li></ul><h2 id="claude-anthropic" tabindex="-1">Claude (Anthropic) <a class="header-anchor" href="#claude-anthropic" aria-label="Permalink to &quot;Claude (Anthropic)&quot;">​</a></h2><p>Claude authenticates via a <strong>long-lived OAuth token</strong>, not a paid API key. Generate a token at <a href="https://claude.ai/settings/tokens" target="_blank" rel="noreferrer">claude.ai/settings/tokens</a> and paste it into the API Keys modal under the <strong>Claude</strong> field.</p><div class="tip custom-block"><p class="custom-block-title">No API credits needed</p><p>The OAuth token uses your Claude subscription instead of the paid API. Premium users get the full Claude model family (Opus, Sonnet, Haiku) plus MCP tool access when a token is saved.</p></div><p><strong>Characteristics</strong></p><ul><li>May use MCP research tools (storytelling, comedy, etc.) during multi-turn generation</li><li>Responses arrive as a single block (not streamed) — intermediate planning is filtered out</li><li>Excellent for complex script writing and fact-checking</li></ul><h2 id="ollama-local-llm" tabindex="-1">Ollama (Local LLM) <a class="header-anchor" href="#ollama-local-llm" aria-label="Permalink to &quot;Ollama (Local LLM)&quot;">​</a></h2><p>Ollama runs models on your local GPU — no API key needed, no internet after the model is pulled. The studio picks up whatever models are loaded on its Ollama service; the model picker shows them automatically in an &quot;Ollama (Free)&quot; optgroup. Availability depends on whether your studio operator has the local-model service enabled.</p><div class="tip custom-block"><p class="custom-block-title">Auto-pull on first boot</p><p>A small starter model is pulled automatically on first boot, so a fresh studio always has at least one usable local model. The recommended default for script writing is <code>qwen2.5:7b</code> (~4.7 GB, 128 k context).</p></div><h3 id="pulling-additional-models" tabindex="-1">Pulling additional models <a class="header-anchor" href="#pulling-additional-models" aria-label="Permalink to &quot;Pulling additional models&quot;">​</a></h3><p>There&#39;s no in-app pull UI today — pulling new local models is an operator task. Ask your administrator if you&#39;d like a different model added.</p><h3 id="suggested-models" tabindex="-1">Suggested models <a class="header-anchor" href="#suggested-models" aria-label="Permalink to &quot;Suggested models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Size</th><th>Best for</th></tr></thead><tbody><tr><td><code>qwen2.5:7b</code></td><td>~4.7 GB</td><td><strong>Recommended default</strong> — script writing, 128 k context</td></tr><tr><td><code>qwen2.5-coder:14b</code></td><td>~9 GB</td><td>Code-aware scripts, reasoning</td></tr><tr><td><code>deepseek-r1:14b</code></td><td>~9 GB</td><td>Reasoning, fact-heavy scripts</td></tr><tr><td><code>llama3.1:8b</code></td><td>~5 GB</td><td>General purpose (lower VRAM)</td></tr><tr><td><code>qwen2.5:1.5b</code></td><td>~986 MB</td><td>Auto-pulled fallback — fast but limited output</td></tr></tbody></table><h3 id="characteristics" tabindex="-1">Characteristics <a class="header-anchor" href="#characteristics" aria-label="Permalink to &quot;Characteristics&quot;">​</a></h3><ul><li>Streams responses token-by-token (like Gemini)</li><li>Fully offline once the model is downloaded</li><li>GPU required for usable speed</li><li>Available to every user — Ollama models appear in the dropdown&#39;s &quot;Ollama (Free)&quot; optgroup whether or not the user has any API keys configured</li></ul><div class="tip custom-block"><p class="custom-block-title">VRAM requirements</p><p>14 B parameter models need ~10 GB VRAM. If you have 8 GB or less, pick 7 B / 8 B variants instead.</p></div><h2 id="model-selection" tabindex="-1">Model selection <a class="header-anchor" href="#model-selection" aria-label="Permalink to &quot;Model selection&quot;">​</a></h2><p>The model dropdown appears in:</p><ul><li>The Script editor&#39;s Revise tab</li><li>AI chat</li><li>The Ideas panel&#39;s inline context hint</li><li>The mobile app&#39;s script detail</li></ul><p>All three providers show in the same dropdown when configured, grouped by provider. Providers that aren&#39;t set up for your account are disabled with a reason (e.g. &quot;No API credits&quot;, &quot;Service unavailable&quot;).</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Gemini</th><th>Claude</th><th>Ollama</th></tr></thead><tbody><tr><td>Auth</td><td>API key</td><td>OAuth token</td><td>None (local)</td></tr><tr><td>Streaming</td><td>Yes (token-by-token)</td><td>No (buffered)</td><td>Yes (token-by-token)</td></tr><tr><td>MCP tools</td><td>No</td><td>Yes</td><td>No</td></tr><tr><td>Speed</td><td>Fast</td><td>Multi-turn possible</td><td>Depends on GPU</td></tr><tr><td>Cost</td><td>API credits</td><td>Included with Claude subscription</td><td>Free (your hardware)</td></tr><tr><td>Internet</td><td>Required</td><td>Required</td><td>Not needed after pull</td></tr></tbody></table>',28)])])}const m=t(r,[["render",i]]);export{p as __pageData,m as default};
